INSERT IGNORE INTO notice (notice_id, created_at, deleted, updated_at, active, writer_id, title, content, pinned, view_count) VALUES
(1, '2026-07-03 09:32:00', b'0', '2026-07-03 09:32:00', b'1', 51, '[공지] SmartHR 인사관리 시스템 오픈 안내', '안녕하세요. SmartHR 인사관리 시스템이 정식 오픈되었습니다. 근태, 휴가, 급여, 인사발령 등 모든 인사 업무를 이곳에서 처리해주세요.', b'1', 27),
(2, '2026-07-08 09:58:00', b'0', '2026-07-08 09:58:00', b'1', 51, '2026년 하계휴가 사용 안내', '하계휴가는 7월~8월 중 자유롭게 사용 가능합니다. 부서별 업무 공백이 없도록 사전에 팀 내 일정을 조율해주시기 바랍니다.', b'1', 47),
(3, '2026-06-23 09:48:00', b'0', '2026-06-23 09:48:00', b'1', 51, '경조사비 지급 규정 안내', '결혼, 출산, 상조 등 경조사 발생 시 경조비 신청 메뉴를 통해 신청해주시면 확인 후 지급됩니다. 증빙서류를 함께 첨부해주세요.', b'0', 9),
(4, '2026-06-08 09:52:00', b'0', '2026-06-08 09:52:00', b'1', 51, '사내 보안 정책 업데이트 안내', '개인정보 보호를 위해 비밀번호를 정기적으로 변경해주시기 바랍니다.', b'0', 19),
(5, '2026-07-18 09:18:00', b'0', '2026-07-18 09:18:00', b'1', 51, '7월 급여 지급일 안내', '7월 급여는 7월 21일에 지급될 예정입니다. 계좌 정보에 변동이 있으신 분은 마감일 전까지 갱신 부탁드립니다.', b'0', 30);
